INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hello TPF, I’m really surprised by the offer from Meesho because the salary doesn’t match what we discussed during the interviews. I’m feeling a bit let down. Can you assist me in resolving this?', 'Siddharth', 'Principal PM', 'Meesho', 'frustrated_candidate', 'offer_issue', 'salary_mismatch', '["acknowledge", "show_empathy", "provide_timeline", "clarify"]'::jsonb, 'Thanks for bringing this to our attention, Siddharth; we''ll promptly reach out to Meesho to find out what happened and keep you updated.', 'hard', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hi there, I just received an offer from Pine Labs, but the salary is significantly lower than what we had discussed. It’s quite disappointing, and I’m hoping you can help me figure this out.', 'Priya', 'Senior PM', 'Pine Labs', 'frustrated_candidate', 'offer_issue', 'salary_mismatch', '["acknowledge", "show_empathy", "set_expectations", "clarify"]'::jsonb, 'We completely understand your frustration, Priya, and we’ll dive into this with Pine Labs to get clarity on the offer immediately.', 'hard', TRUE);
