INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hello TPF, I hope you’re well. I applied for a Product Manager position at Paytm, but I see it’s no longer listed. This has left me feeling really uncertain about my application. Can you clarify what’s going on?', 'Saanvi', 'Product Manager', 'Paytm', 'confused_candidate', 'process_confusion', 'role_no_longer_listed', '["acknowledge", "apologize", "clarify", "reassure", "show_empathy"]'::jsonb, 'Your concerns are valid, and we appreciate your patience as we look into this for you!', 'easy', TRUE);
