INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hi TPF team, I’m thrilled to get an offer from Razorpay for the Principal PM role, but they need someone to start right away. Unfortunately, I’m stuck with a 3-month notice period and I’m worried I might lose this opportunity. What should I do?', 'Divya', 'Principal PM', 'Razorpay', 'concerned_candidate', 'offer_issue', 'notice_period_issue', '["acknowledge", "apologize", "show_empathy", "explain_process", "set_expectations"]'::jsonb, 'We totally empathize with your situation and will support you in crafting a message to Razorpay to communicate your notice period and discuss potential flexibility.', 'medium', TRUE);
