INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('I can''t believe the candidate we agreed on for the Senior PM position at Zomato didn’t even show up for the interview. This is incredibly frustrating! We need dependable candidates, and this is not the first time this has happened. Can you please look into this?', 'Riya Sharma', 'Senior PM', 'Zomato', 'angry_client', 'general', 'client_candidate_no_show', '["acknowledge", "apologize", "clarify", "show_empathy"]'::jsonb, 'We''ll investigate this matter and ensure better communication with candidates moving forward.', 'hard', TRUE);
