INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hey TPF team, I''m really frustrated with the candidates you’ve been sending us for the Senior PM role at BharatPe. They don’t seem to have the right experience or skills we’re looking for, and it’s slowing down our hiring process. Can we please have a chat to align on exactly what we need?', 'Ananya', 'Senior PM', 'BharatPe', 'professional_client', 'general', 'client_profile_mismatch', '["acknowledge", "show_empathy", "clarify", "reassure", "set_expectations"]'::jsonb, 'We appreciate your feedback, Ananya, and we''ll work closely with you to refine our search and ensure we align with your expectations moving forward.', 'hard', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hi there, I wanted to reach out because the candidates we’ve been receiving for the Principal PM position at CRED just aren’t hitting the mark. It’s becoming a bit frustrating since we’re eager to fill this role. Can we set up a meeting to discuss what’s going wrong?', 'Rahul', 'Principal PM', 'CRED', 'professional_client', 'general', 'client_profile_mismatch', '["acknowledge", "apologize", "explain_process", "reassure", "show_empathy"]'::jsonb, 'Thank you for bringing this to our attention, Rahul; we’re committed to finding the right fit and would love to discuss specifics with you to improve our candidate selection.', 'hard', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hello TPF team, I’m reaching out because the candidates for the Senior PM role at Razorpay aren''t quite what we expected. We’re really looking for someone with more hands-on experience, and I’m feeling a bit concerned about the quality of applicants. Can we talk soon?', 'Priya', 'Senior PM', 'Razorpay', 'professional_client', 'general', 'client_profile_mismatch', '["acknowledge", "show_empathy", "clarify", "reassure", "set_expectations"]'::jsonb, 'I completely understand your concerns, Priya, and I assure you that we will take immediate steps to better align our candidate recommendations with your needs.', 'hard', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hey Team, I hope you’re doing well! I’ve been eagerly waiting for my performance review feedback for quite some time now, and it’s starting to make me anxious. Could you please let me know if there’s a timeline for when I might receive it? I’m really looking forward to understanding my role better and how I can contribute more effectively.', 'Riya Sharma', 'Community Manager', 'Zomato', 'concerned_candidate', 'delay', 'internal_team_delayed_feedback', '["acknowledge", "show_empathy", "provide_timeline", "set_expectations"]'::jsonb, 'We understand your concern, Riya, and are actively working to provide you with the feedback you need soon — thank you for your patience!', 'medium', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hi TPF Team, I hope everything is great! It’s been a few weeks since I’ve been waiting for clarity on my role and feedback from my last review. I’m feeling a bit lost and would really appreciate any updates you could share. Thanks for all your support!', 'Arjun Mehta', 'Talent Associate', 'Paytm', 'concerned_candidate', 'delay', 'internal_team_delayed_feedback', '["acknowledge", "reassure", "explain_process", "set_expectations"]'::jsonb, 'We truly appreciate your patience, Arjun, and we''re working on getting back to you with clarity shortly — hang tight!', 'medium', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hello Team, I hope all is well with you! I wanted to reach out regarding the performance review feedback I’ve been expecting for some time now. It’s been hard not knowing where I stand, and I’d love any info or timeline on when I can expect to hear back. Thank you!', 'Nisha Rao', 'Operations Manager', 'Swiggy', 'concerned_candidate', 'delay', 'internal_team_delayed_feedback', '["acknowledge", "clarify", "show_empathy", "provide_timeline"]'::jsonb, 'We hear you, Nisha, and are committed to providing you with the feedback soon — thank you for your understanding!', 'medium', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hi TPF team, I hope you''re doing well! I applied for the Product Manager position at Zepto a few months ago but unfortunately didn’t get through. I’m really passionate about the role and have been working on enhancing my skills since then. Would my application be reconsidered if I reapply? Thank you for your guidance!', 'Riya Sharma', 'Product Manager', 'Zepto', 'concerned_candidate', 'feedback_request', 'candidate_reapplying_after_rejection', '["acknowledge", "show_empathy", "clarify", "reassure", "explain_process"]'::jsonb, 'Absolutely, Riya! We appreciate your determination and would love to see your new application; it reflects your growth and passion.', 'medium', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hello TPF team, I hope you’re all doing great! I had applied for the Senior PM role at Swiggy a few months back but didn’t make it through. I’ve taken some courses to strengthen my skills in the meantime and I’m eager to know if I can be considered again for similar roles. Thank you!', 'Aarav Mehta', 'Senior PM', 'Swiggy', 'concerned_candidate', 'feedback_request', 'candidate_reapplying_after_rejection', '["acknowledge", "show_empathy", "reassure", "provide_timeline", "set_expectations"]'::jsonb, 'Hi Aarav, we love to see candidates who are dedicated to growth! Please feel free to reapply, and we''ll make sure to review your application thoroughly.', 'medium', TRUE);
INSERT INTO scenarios (message, sender_name, role_applied, company_name, tone, category, situation_type, expected_points, ideal_response_tone, difficulty, active) VALUES ('Hi team, I hope everything is going well! I had previously applied for a Product Manager position at CRED but was not selected. Since then, I have gained more experience and insights, and I would love to know if I could be reconsidered if I reapply. Thanks for your help!', 'Priya Kapoor', 'Product Manager', 'CRED', 'concerned_candidate', 'feedback_request', 'candidate_reapplying_after_rejection', '["acknowledge", "show_empathy", "clarify", "reassure", "explain_process"]'::jsonb, 'Hi Priya! Your commitment to growth is impressive, and we would be happy to consider your reapplication; just let us know when you’re ready!', 'medium', TRUE);

